const items = $input.all();
for (let i = 0; i < items.length; i++) {
  const payload = items[i].json;

  if (!payload.materiais || !Array.isArray(payload.materiais) || payload.materiais.length === 0) {
    items[i].json.materiais_a_parte = true;
    items[i].json.mensagem_materiais = "Materiais a serem faturados à parte mediante Avaliação Técnica ou repassados ao condomínio.";
    items[i].json.custo_materiais_total = 0;
  } else {
    items[i].json.materiais_a_parte = false;
    let totalMaterial = 0;
    for (let mat of payload.materiais) {
       totalMaterial += (mat.quantidade || 0) * (mat.preco_unitario || 0);
    }
    items[i].json.custo_materiais_total = totalMaterial;
  }
}
return items;
